import socket
import json
import threading
import time

class GameServer:
    def __init__(self, host='0.0.0.0', port=27015):
        self.host = host
        self.port = port
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.running = True
        self.game_state = self._initialize_game_state()
        self.last_update_time = time.time()

    def _initialize_game_state(self):
        return {
            "server_name": "My Awesome Game Server",
            "map": "de_dust2",
            "players_online": 5,
            "max_players": 16,
            "game_mode": "Deathmatch",
            "version": "1.0.0",
            "ping": 50,
            "private": False,
            "password_protected": False,
            "players": [
                {"name": "Player1", "score": 120, "kills": 15, "deaths": 5},
                {"name": "Player2", "score": 90, "kills": 10, "deaths": 3},
                {"name": "Player3", "score": 75, "kills": 8, "deaths": 7},
                {"name": "Player4", "score": 60, "kills": 7, "deaths": 6},
                {"name": "Player5", "score": 45, "kills": 5, "deaths": 8},
                {"name": "Player6", "score": 110, "kills": 14, "deaths": 4},
                {"name": "Player7", "score": 85, "kills": 9, "deaths": 2},
                {"name": "Player8", "score": 70, "kills": 7, "deaths": 5},
                {"name": "Player9", "score": 55, "kills": 6, "deaths": 7},
                {"name": "Player10", "score": 40, "kills": 4, "deaths": 9},
                {"name": "Player11", "score": 100, "kills": 12, "deaths": 3},
                {"name": "Player12", "score": 80, "kills": 8, "deaths": 1},
                {"name": "Player13", "score": 65, "kills": 6, "deaths": 4},
                {"name": "Player14", "score": 50, "kills": 5, "deaths": 6},
                {"name": "Player15", "score": 35, "kills": 3, "deaths": 10},
            ]
        }

    def _update_game_state_periodically(self):
        # Simulate dynamic game state
        current_time = time.time()
        if current_time - self.last_update_time > 5: # Update every 5 seconds
            self.game_state["players_online"] = len(self.game_state["players"])
            self.game_state["map"] = "de_mirage" if self.game_state["map"] == "de_dust2" else "de_dust2"
            self.game_state["ping"] = (self.game_state["ping"] % 100) + 20 # Keep ping between 20-120
            # Shuffle players to simulate activity
            import random
            random.shuffle(self.game_state["players"])
            for player in self.game_state["players"]:
                player["score"] += random.randint(0, 5)
                player["kills"] += random.randint(0, 1)
            self.last_update_time = current_time

    def _handle_status_query(self, addr):
        self._update_game_state_periodically()
        # Prepare the response
        response_data = json.dumps(self.game_state)
        # For UDP, large responses might need to be fragmented or sent in chunks.
        # However, for a simple game server browser, a single large UDP packet
        # (up to ~65KB, though often limited by MTU to ~1500 bytes without fragmentation)
        # is often used. We'll send it as one packet.
        # Ensure the response is encoded to bytes.
        response_bytes = response_data.encode('utf-8')

        print(f"[{time.strftime('%H:%M:%S')}] Sending {len(response_bytes)} bytes status to {addr}")

        try:
            self.sock.sendto(response_bytes, addr)
        except Exception as e:
            print(f"Error sending response to {addr}: {e}")

    def _listen_for_queries(self):
        print(f"UDP Game Server listening on {self.host}:{self.port}")
        while self.running:
            try:
                data, addr = self.sock.recvfrom(65507) # Max UDP packet size
                query = data.decode('utf-8').strip().lower()

                if query == "getstatus":
                    # Handle status query in a new thread to avoid blocking the main loop
                    # if response sending is slow or there are many requests.
                    # For UDP, this is less critical than TCP, but good practice.
                    threading.Thread(target=self._handle_status_query, args=(addr,)).start()
                else:
                    print(f"[{time.strftime('%H:%M:%S')}] Received unknown query '{query}' from {addr}")
                    # Optionally send an error response
                    self.sock.sendto(b"UNKNOWN_COMMAND", addr)

            except socket.timeout:
                continue # Just continue listening
            except Exception as e:
                if self.running:
                    print(f"Server error: {e}")
                break

    def start(self):
        self.sock.settimeout(1.0) # Timeout for recvfrom to allow checking self.running
        self.server_thread = threading.Thread(target=self._listen_for_queries)
        self.server_thread.start()

    def stop(self):
        print("Stopping server...")
        self.running = False
        if self.server_thread.is_alive():
            self.server_thread.join(timeout=5) # Wait for the thread to finish
        self.sock.close()
        print("Server stopped.")

