    server = GameServer()
    server.start()

    try:
        # Keep the main thread alive while the server thread runs
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        server.stop()
    except Exception as e:
        print(f"Main thread error: {e}")
        server.stop()